// JS Checkbox Select All & Auto-Folding Control
const master = document.getElementById('terms-all-checkbox');
const subs = document.querySelectorAll('.sub-checkbox');
const panel = document.getElementById('terms-list-panel');
const detailBtns = document.querySelectorAll('.term-detail-btn');

// 전체 체크박스 토글 시 전체 선택 및 목록 접기/열기
master.addEventListener('change', () => {
  const isChecked = master.checked;
  subs.forEach(cb => cb.checked = isChecked);
  panel.style.maxHeight = isChecked ? '0px' : panel.scrollHeight + 'px';
});

// 개별 체크박스 토글 시 마스터 상태 갱신 및 자동 접기/열기
subs.forEach(cb => {
  cb.addEventListener('change', () => {
    const checkedCount = document.querySelectorAll('.sub-checkbox:checked').length;
    const isAllChecked = (checkedCount === subs.length);
    const wasChecked = master.checked;
    master.checked = isAllChecked;

    if (isAllChecked && !wasChecked) {
      panel.style.maxHeight = '0px';
    } else if (!isAllChecked && wasChecked) {
      panel.style.maxHeight = panel.scrollHeight + 'px';
    }
  });
});

// 개별 약관 내용 접기/펼치기 및 부모 영역 높이 조정
detailBtns.forEach(btn => {
  btn.addEventListener('click', () => {
    const target = document.getElementById(btn.getAttribute('data-target'));
    btn.classList.toggle('active');
    target.style.maxHeight = btn.classList.contains('active') ? target.scrollHeight + 'px' : '0px';
    setTimeout(() => {
      if (panel.style.maxHeight !== '0px') {
        panel.style.maxHeight = panel.scrollHeight + 'px';
      }
    }, 300);
  });
});

