/* 5. Checkbox Terms Accordion Styles */
.terms-component {
  background-color: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 16px;
  padding: 16px;
  display: flex;
  flex-direction: column;
}

.terms-master-row {
  padding-bottom: 12px;
  border-bottom: 1.5px solid #f1f5f9;
}

.terms-checkbox-label {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  cursor: pointer;
  user-select: none;
}

.terms-checkbox {
  display: none;
}

.checkbox-custom {
  width: 20px; height: 20px;
  border: 2px solid #cbd5e1;
  border-radius: 6px;
  position: relative;
  transition: all 0.2s ease;
}

.terms-checkbox:checked + .checkbox-custom {
  background-color: #6366f1;
  border-color: #6366f1;
}

.terms-checkbox:checked + .checkbox-custom::after {
  content: '';
  position: absolute;
  left: 6px; top: 2px;
  width: 5px; height: 10px;
  border: solid white;
  border-width: 0 2px 2px 0;
  transform: rotate(45deg);
}

.terms-collapsible-list {
  max-height: 200px;
  overflow: hidden;
  transition: max-height 0.4s ease;
}

.term-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 0;
}

.term-detail-btn {
  background: transparent; border: none; cursor: pointer;
}

.term-detail-content {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.3s ease;
}
